import React, { useState } from "react";
import { Link, useLocation } from "react-router-dom";

const Navbar = () => {
  const location = useLocation();
  const [menuOpen, setMenuOpen] = useState(false);

  const isActive = (path) => location.pathname === path;

  return (
    <nav className="glass sticky top-0 z-50 px-6 py-4">
      <div className="max-w-7xl mx-auto flex items-center justify-between">
        {/* Logo */}
        <Link to="/" className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-indigo-600 flex items-center justify-center pulse-glow">
            <span className="text-xl">🔐</span>
          </div>
          <div>
            <h1 className="text-white font-bold text-lg leading-none">EvidenceLocker</h1>
            <p className="text-indigo-400 text-xs">Blockchain Secured</p>
          </div>
        </Link>

        {/* Desktop Menu */}
        <div className="hidden md:flex items-center gap-2">
          <Link
            to="/"
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ${
              isActive("/")
                ? "bg-indigo-600 text-white"
                : "text-slate-400 hover:text-white hover:bg-white/10"
            }`}
          >
            🏠 Home
          </Link>
          <Link
            to="/upload"
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ${
              isActive("/upload")
                ? "bg-indigo-600 text-white"
                : "text-slate-400 hover:text-white hover:bg-white/10"
            }`}
          >
            📤 Upload Evidence
          </Link>
          <Link
            to="/verify"
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ${
              isActive("/verify")
                ? "bg-indigo-600 text-white"
                : "text-slate-400 hover:text-white hover:bg-white/10"
            }`}
          >
            🔍 Verify Evidence
          </Link>
        </div>

        {/* Mobile Menu Button */}
        <button
          className="md:hidden text-white"
          onClick={() => setMenuOpen(!menuOpen)}
        >
          {menuOpen ? "✕" : "☰"}
        </button>
      </div>

      {/* Mobile Menu */}
      {menuOpen && (
        <div className="md:hidden mt-4 flex flex-col gap-2 px-4 pb-4">
          <Link to="/" className="text-slate-300 hover:text-white py-2" onClick={() => setMenuOpen(false)}>🏠 Home</Link>
          <Link to="/upload" className="text-slate-300 hover:text-white py-2" onClick={() => setMenuOpen(false)}>📤 Upload Evidence</Link>
          <Link to="/verify" className="text-slate-300 hover:text-white py-2" onClick={() => setMenuOpen(false)}>🔍 Verify Evidence</Link>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
